import os
import anthropic
from typing import Any

def get_claude_client() -> Any:
    """Return the appropriate Anthropic client based on environment config."""
    backend = os.environ.get("CLAUDE_BACKEND", "direct")

    if backend == "bedrock":
        return anthropic.AnthropicBedrock(
            aws_region=os.environ.get("AWS_REGION", "us-east-1"),
        )
    elif backend == "vertex":
        return anthropic.AnthropicVertex(
            project_id=os.environ["GCP_PROJECT_ID"],
            region=os.environ.get("GCP_REGION", "us-east5"),
        )
    else:
        return anthropic.Anthropic(
            api_key=os.environ["ANTHROPIC_API_KEY"],
        )

# Use once at app startup
client = get_claude_client()

def complete(prompt: str, model: str = "claude-haiku-4-5-20251001") -> str:
    # AnthropicBedrock and AnthropicVertex share the same interface
    response = client.messages.create(
        model=model,
        max_tokens=1024,
        messages=[{"role": "user", "content": prompt}]
    )
    return response.content[0].text
